final:
module binary_counter
    (
        input clk,
        input enable,
        input rst,
        output reg [3:0] count
    );

    reg [3:0] unused_count_reg;

    always @(posedge clk) begin
        if (rst) begin
            unused_count_reg <= 4'b0000;
        end else if (enable) begin
            unused_count_reg <= unused_count_reg + 1;
        end
    end

    assign count = unused_count_reg;

endmodule
